## 代码

> 这个代码是我在工作中遇到的，当时需要使用net/http库发起SOCKS代理请求，所以就写了这个代码。
> 
> 这个代码是使用net/http库发起SOCKS代理请求，所以需要使用`golang.org/x/net/proxy`库。


```go
package utils

import (
	"errors"
	"io/ioutil"
	"net/http"

	"golang.org/x/net/proxy"
)

func HttpSendSock(url string) (string, error) {

	// 设置代理信息
	proxyURL := "demo.example.com:8080"
	proxyUser := "admin"
	proxyPass := "123456"

	// 创建 SOCKS5 代理的身份验证
	auth := proxy.Auth{User: proxyUser, Password: proxyPass}

	// 通过代理创建 SOCKS5 Dialer
	dialer, err := proxy.SOCKS5("tcp", proxyURL, &auth, proxy.Direct)
	if err != nil {
		return "", errors.New("无法创建代理" + err.Error())
	}

	// 创建 HTTP Transport，并使用该 Transport 通过 SOCKS5 代理发送请求
	httpTransport := &http.Transport{}
	httpTransport.Dial = dialer.Dial

	// 创建 HTTP Client，使用配置了代理的 Transport
	client := &http.Client{
		Transport: httpTransport,
	}

	// 发送 GET 请求
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return "", errors.New("无法发起请求" + err.Error())
	}

	// 执行请求
	resp, err := client.Do(req)
	if err != nil {
		return "", errors.New("执行请求错误" + err.Error())
	}
	defer resp.Body.Close()

	// 读取并打印响应内容
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return "", errors.New("读取内容失败" + err.Error())
	}

	return string(body), nil
}
```

## 概述

实际项目开发中有些时候确实需要用到日志系统，打印日志信息到`log`文件中，方便排查问题。

为了方便就自己写了一个日志系统，方便使用，具体代码参考下文。

## 代码

> 包名暂定`manager`，具体包名可以自行修改，因为我把他作为了一个日志管理，所以包名就叫`manager`。

```go
package manager

import (
	"fmt"
	"log"
	"os"
	"path/filepath"
	"sync"
	"time"
)

// LogLevel 定义日志级别
type LogLevel int

const (
	DEBUG LogLevel = iota
	INFO
	WARN
	ERROR
)

var (
	logFile   *os.File
	logger    *log.Logger
	once      sync.Once
	logMutex  sync.Mutex
	logLevels = map[LogLevel]string{
		DEBUG: "DEBUG",
		INFO:  "INFO",
		WARN:  "WARN",
		ERROR: "ERROR",
	}
)

// InitLogger 初始化日志系统
func InitLogger(logPath string) error {
	var err error
	once.Do(func() {
		// 确保日志目录存在
		logDir := filepath.Dir(logPath)
		if err = os.MkdirAll(logDir, 0755); err != nil {
			return
		}

		// 打开日志文件，如果不存在则创建，追加写入
		logFile, err = os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0644)
		if err != nil {
			return
		}

		// 初始化logger
		logger = log.New(logFile, "", 0)
	})
	return err
}

// LogMessage 记录日志消息
func LogMessage(level LogLevel, format string, args ...interface{}) {
	if logger == nil {
		return
	}

	logMutex.Lock()
	defer logMutex.Unlock()

	// 格式化时间
	timestamp := time.Now().Format("2006-01-02 15:04:05.000")

	// 格式化消息
	message := fmt.Sprintf(format, args...)

	// 完整的日志条目
	logEntry := fmt.Sprintf("[%s] [%s] %s", timestamp, logLevels[level], message)

	// 写入日志
	logger.Println(logEntry)
}

// CloseLogger 关闭日志文件
func CloseLogger() {
	if logFile != nil {
		logFile.Close()
	}
}

// 便捷的日志记录方法
func Debug(format string, args ...interface{}) {
	LogMessage(DEBUG, format, args...)
}

func Info(format string, args ...interface{}) {
	LogMessage(INFO, format, args...)
}

func Warn(format string, args ...interface{}) {
	LogMessage(WARN, format, args...)
}

func Error(format string, args ...interface{}) {
	LogMessage(ERROR, format, args...)
}

// RotateLog 日志文件轮转
func RotateLog(logPath string) error {
	logMutex.Lock()
	defer logMutex.Unlock()

	// 关闭当前日志文件
	if logFile != nil {
		logFile.Close()
	}

	// 生成新的日志文件名（带时间戳）
	timestamp := time.Now().Format("20060102150405")
	ext := filepath.Ext(logPath)
	newPath := fmt.Sprintf("%s.%s%s", logPath[:len(logPath)-len(ext)], timestamp, ext)

	// 重命名当前日志文件
	if err := os.Rename(logPath, newPath); err != nil {
		return fmt.Errorf("rotate log file failed: %v", err)
	}

	// 创建新的日志文件
	var err error
	logFile, err = os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0644)
	if err != nil {
		return fmt.Errorf("create new log file failed: %v", err)
	}

	// 更新logger
	logger = log.New(logFile, "", 0)
	return nil
}
```

